const object = queries.fetchConfigDetails.data.Dimensions;
let tempArr = [];
for (const property in object) {
  if(object[property].dimension_name.includes("LEGACY_")) {
    //isMarketplaceAware.setValue(true);
    await actions.setPageVariable("isMarketplaceAware",true)
  } 
  else {
    const t = {};
    t.Level = "L" + (parseInt(property)+1);
    t.Key = object[property].dimension_name;
    t.type = object[property].type.slice(5).toLocaleLowerCase();
    t.val = "";
    tempArr = [...tempArr, t];
  }
}
tempArr.sort((a,b) => {
  const numA = parseInt(a.Level.substring(1)); // Extract number from string, e.g., "L2" becomes 2
  const numB = parseInt(b.Level.substring(1)); // Extract number from string, e.g., "L3" becomes 3
  return numA - numB;});
//dimensionArray.setValue(tempArr);
await actions.setPageVariable("dimensionArray",tempArr)
